//2.7.101 | 2022-01-03 | raj | DFCT0010628	"Suspense Date for Acknowledgement Tasker Type" System setting is NOT following "OU Override Schedule"
// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === ''){
		return;
	}

	onTypeChange();
	// DFCT0011108
	function onTypeChange(){
		// This script uses the addDays function from Script Include MyDateTimeAjax

		// STRY0127550 - get the value instead of the display value and compare to a constant instead of a hard coded string
		var taskerDisplayValue = g_form.getDisplayValue('tasker_type');
		var currentTaskType = g_scratchpad.taskerTypesDisplayValues[taskerDisplayValue];

		if(currentTaskType != undefined && currentTaskType ==  g_scratchpad.taskerTypesConstants.acknowledgement){		
			var ajax = new GlideAjax('MyDateTimeAjax');
			ajax.addParam('sysparm_name', 'addDaysAcknowledgementSuspenseDate');
			// STRY0102134 - pass taskin so we can look up Primary Office OU and check for override schedule
			ajax.addParam('sysparam_task_id',g_form.getUniqueValue());
			// DFCT0010628
			ajax.addParam('sysparam_primary_OU_id',g_form.getValue("primary_office"));

			ajax.getXML(function(response){
				var answer = response.responseXML.documentElement.getAttribute("answer");
				if(answer){
					g_form.setValue('suspense_date', answer);
				}
				return;
			});
		}		
	}

}
